  function levelOptions(k,value){ return levels[k].map(v=>`<option value="${v}" ${value===v?"selected":""}>${v} - ${esc(levelText[k][v])}</option>`).join(""); }
  function levelHelp(){ return `<details class="levelHelp"><summary>Comment choisir les tests initiaux ?</summary><div class="helpGrid">${Object.keys(levelNames).map(k=>`<div><strong>${levelNames[k]}</strong><p>${levels[k].map(v=>`${v}: ${levelText[k][v]}`).join(" · ")}</p></div>`).join("")}</div></details>`; }

  function shell(content){ const nav=["today","plan","session","exercises","stats","settings"]; const names={today:"Aujourd'hui",plan:"Plan",session:"Séance",exercises:"Exos",stats:"Stats",settings:"Réglages"}, icons={today:"⌂",plan:"▦",session:"▶",exercises:"◉",stats:"◷",settings:"⚙"}, notice=[updatePrompt(),state.settings.hideInstallPrompt?pwaPrompt().replace("pwaPrompt","pwaPrompt hidden"):pwaPrompt(),state.ui.message?`<p class="notice toastNotice">${esc(state.ui.message)}</p>`:""].join(""); return `<main class="app"><div class="fixedShell"><header class="top"><div class="brand"><img class="logo" src="./icon.svg" alt="ResurGo Fitness"><span>ResurGo Fitness</span></div><span class="pill">${navigator.onLine?"Online":"Offline"} · v${APP_VERSION}</span></header></div><nav class="tabs">${nav.map(v=>`<button class="tab ${state.ui.view===v?"active":""}" data-view="${v}"><span>${icons[v]}</span><span>${names[v]}</span></button>`).join("")}</nav><div class="toastLayer">${notice}</div><section class="content">${content}</section>${modalLayer()}</main>`; }
  function today(){ const p=profile(); if(!p) return `<section class="hero"><p class="eyebrow">Coach sportif local-first</p><h1>ResurGo Fitness</h1><p>PWA offline avec séances guidées, exercices détaillés, stats, saisie course/balance et Worker Garmin optionnel.</p>${newProfileBox()}</section>`; const d=decision(p), m=latestMetric(), g=goalInfo(p), pick=coachPickToday(p), s=pick.session, next=nextPlannedSession(), done=!plan().length&&weekPlan().length; return `<section class="grid"><h1>Aujourd'hui</h1><div class="grid two todayMain"><article class="panel"><p class="eyebrow">Profil actif</p><h2>${esc(p.name)}</h2><div class="row"><span>Objectif</span><strong>${p.startWeightKg||"?"} → ${p.targetWeightKg||"?"} kg</strong></div><div class="row"><span>Cadence cible</span><strong>${esc(g.text)}</strong></div><div class="row"><span>Poids récent</span><strong>${m?m.weightKg+" kg":"À saisir"}</strong></div><div class="row coachOrientation"><span>Orientation du coach</span><strong class="status ${d[0]}">${d[1]}</strong></div><p class="muted">${d[2]}</p><div class="actions compactActions twoButtons"><button class="secondary" id="openMetricModal">Ajouter pesée</button><button class="secondary" id="openActivityModal">Ajouter activité</button></div></article><article class="panel quickPanel"><h2>Check rapide</h2><p class="muted">5 = tout va bien, 0 = alerte rouge.</p>${bodyStateControls("quick",p,"quickSmiley")}</article><article class="panel todaySession ${s?"":"restDay"}"><p class="eyebrow">${esc(pick.title)}</p><h2>${s?esc(s.title):"Repos"}</h2><p class="muted">${s?`${dayLabel(s.date||TODAY)} · ${typeLabel(s.type)} · ${s.minutes} min · ${s.exerciseIds.length} blocs`:(next?`Prochaine séance : ${dayLabel(next.date||TODAY)} · ${next.title}`:"Aucune séance active.")}</p><p class="muted">${esc(pick.reason)}</p><div class="actions">${s?`<button class="primary" id="startToday">Démarrer</button>`:""}${done?`<button class="primary" id="nextWeek">Semaine suivante</button>`:""}<button class="secondary" id="goPlan">Voir la semaine</button><button class="secondary" id="activeRest">Repos actif</button></div></article></div><p class="notice">Sécurité : stop en cas de douleur irradiée, faiblesse, engourdissement, douleur forte ou symptôme inquiétant.</p></section>`; }
  function planView(){ if(!profile()) return needProfile(); const p=profile(), items=weekPlan(), short=!!items[0]?.short, agenda=weekAgenda(p), pick=coachPickToday(p), done=!plan().length&&items.length; return `<section class="grid"><h1>Plan adaptatif</h1><div class="switchRow"><button class="${short?"secondary":"primary"} ${short?"":"isActive"}" id="regenNormal">Semaine normale</button><button class="${short?"primary isActive":"secondary"}" id="regenShort">Semaine minimale viable</button></div><article class="panel planSummary"><h2>Semaine ${items[0]?.week||1}</h2><div class="chips">${frequencySummary(p).map(x=>`<span>${esc(x)}</span>`).join("")}</div>${pick.session?`<p class="muted">Aujourd'hui le coach conseille : ${esc(pick.session.title)}. ${esc(pick.reason)}</p>`:`<p class="muted">Aujourd'hui le coach conseille : repos. ${esc(pick.reason)}</p>`}${done?`<button class="primary" id="nextWeek">Générer semaine suivante</button>`:""}</article><div class="weekAgenda">${agenda.map(d=>d.session?`<article class="panel dayCard ${d.session.completedAt?"doneDay":""}"><p class="eyebrow">${dayLabel(d.date)} · ${typeLabel(d.session.type)}${d.session.completedAt?" · fait":""}</p><h2>${esc(d.session.title)}</h2><p class="muted">${d.session.minutes} min · ${d.session.exerciseIds.length} blocs</p><div class="chips">${d.session.exerciseIds.map(id=>`<span>${exercise(id).name}</span>`).join("")}</div>${d.session.completedAt?`<span class="status green">Terminé</span>`:`<button class="primary" data-start="${d.session.id}">Lancer</button>`}</article>`:`<article class="panel dayCard restDay"><p class="eyebrow">${dayLabel(d.date)}</p><h2>Repos</h2><p class="muted">Récupération, marche douce possible si tu veux bouger.</p></article>`).join("")}</div></section>`; }

  // Rassembler ici les vues de navigation principales :
  // accueil, plan, séance et bibliothèque.
  function sessionView(){ const r=run(); if(!r) return `<section class="grid"><h1>Séance</h1><article class="panel"><p>Aucune séance en cours.</p><button class="primary" id="startToday">Lancer la prochaine séance</button></article></section>`; const s=state.plans.find(x=>x.id===r.sessionId), x=currentEx(), logs=r.logs.filter(l=>l.exerciseId===x.id), done=logs.length, pct=Math.round(done/x.sets*100), currentSet=Math.min(done+1,x.sets); if(r.mode==="resting") return `<section class="session rest"><article class="panel coach workoutCoach"><p class="eyebrow">${s.title} · récupération</p><h1>Repos</h1><div class="timer restTimer" id="timer">${sec(Math.max(left,0))}</div><p class="muted">${esc(r.restNext?.label||"Série suivante")}</p><div class="coachCue"><strong>Reprise manuelle</strong><span>Respire, bois une gorgée si besoin, vérifie douleur et technique. La suite démarre quand tu appuies.</span></div><div class="actions"><button class="primary" id="continueAfterRest">Commencer quand je suis prêt</button><button class="secondary" id="skipRest">Passer le repos</button><button class="danger" id="abortSession">Abandonner</button></div></article></section>`; return `<section class="session"><div class="media sessionMedia">${media(x,true)}</div><article class="panel coach workoutCoach"><p class="eyebrow">${s.title} · exercice ${r.exerciseIndex+1}/${s.exerciseIds.length}</p><h1>${x.name}</h1><div class="workoutMeta"><span>${x.type==="time"?sec(x.seconds):`${x.reps} reps`}</span><span>${x.sets} séries</span><span>${x.rest||0}s repos</span></div><div class="setbox premiumSet"><div><strong>Série ${currentSet} / ${x.sets}</strong><span>${pct}% terminé</span></div><progress max="${x.sets}" value="${done}"></progress></div><div class="coachCue"><strong>Objectif</strong><span>${x.short}</span></div><details class="cueDetails"><summary>Consignes, sécurité et zones</summary>${targetPanel(x)}<ol>${x.steps.map(v=>`<li>${esc(v)}</li>`).join("")}</ol><p class="notice">${x.safety}</p></details><div class="timer" id="timer">${x.type==="time"?sec(left||x.seconds):`${x.reps} reps`}</div><div class="actions sessionActions"><button class="primary" id="startTimer">${x.type==="time"?"Lancer timer":"Lire consignes"}</button><button class="primary" id="okSet">Réussi</button><button class="secondary" id="partialSet">Dur</button><button class="danger" id="painSet">Stop</button><button class="secondary" id="speakCue">Voix</button><button class="danger" id="abortSession">Quitter</button></div></article></section>`; }
  function exercisesView(){ const f=state.ui.filter, q=(state.ui.search||"").toLowerCase(), draft=state.ui.searchDraft ?? state.ui.search ?? "", fam=[...new Set(ex.map(x=>x.family))], list=ex.filter(x=>(f==="all"||x.family===f)&&`${x.name} ${familyLabel(x.family)} ${x.short} ${x.steps.join(" ")}`.toLowerCase().includes(q)); return `<section class="grid"><h1>Bibliothèque</h1><div class="panel"><form class="searchForm compactSearch" id="exerciseSearchForm"><label>Recherche<input id="searchDraft" type="search" value="${esc(draft)}" placeholder="genou, dos, pompe, course..." autocomplete="off" enterkeyhint="search"></label></form><div class="grid two"><label>Famille<select id="familyFilter"><option value="all">Toutes</option>${fam.map(x=>`<option value="${x}" ${f===x?"selected":""}>${familyLabel(x)}</option>`).join("")}</select></label><p class="muted">${list.length} exercices · vidéo online, fiche et animation offline</p></div></div><div class="exerciseGrid">${list.map(card).join("")}</div></section>`; }
  function statsValue(v, suffix=""){ return v||v===0 ? `${v}${suffix}` : "--"; }
  function lastRun(acts){ return [...acts].reverse().find(a=>["run","walk","bike","cardio"].includes(a.type))||null; }
  function paceLabel(a){ if(!a?.durationSeconds||!a?.distanceKm) return "--"; const secKm=a.durationSeconds/a.distanceKm; return `${Math.floor(secKm/60)}:${String(Math.round(secKm%60)).padStart(2,"0")}/km`; }
  function gauge(value, color="var(--blue)"){ const v=Math.max(0,Math.min(100,Number(value)||0)); return `<svg class="gauge" viewBox="0 0 120 88" aria-hidden="true"><path d="M20 72 A40 40 0 0 1 100 72" pathLength="100" fill="none" stroke="var(--gauge-track)" stroke-width="10" stroke-linecap="round"/><path d="M20 72 A40 40 0 0 1 100 72" pathLength="100" fill="none" stroke="${color}" stroke-width="10" stroke-dasharray="${v} 100" stroke-linecap="round"/><text x="60" y="64" text-anchor="middle" fill="var(--ink)" font-size="24" font-weight="900">${Math.round(v)}</text></svg>`; }
  function spark(rows,key,color="var(--blue)"){ const vals=rows.map(r=>Number(r[key])).filter(Number.isFinite); if(vals.length<2) return "<p class='metricEmpty'>Pas assez de données</p>"; const min=Math.min(...vals), max=Math.max(...vals), pts=vals.map((v,i)=>`${8+i*104/(vals.length-1)},${54-((v-min)/Math.max(1,max-min))*42}`).join(" "); return `<svg class="spark" viewBox="0 0 120 64" aria-hidden="true"><polyline points="${pts}" fill="none" stroke="${color}" stroke-width="4" stroke-linecap="round" stroke-linejoin="round"/><circle cx="${8+(vals.length-1)*104/(vals.length-1)}" cy="${54-((vals[vals.length-1]-min)/Math.max(1,max-min))*42}" r="4" fill="${color}"/></svg>`; }
  function metricCard(o){ return `<article class="metricCard ${o.tall?"metricTall":""}"><div class="metricHead"><span class="metricIcon" style="color:${o.color||"var(--blue)"}">${o.icon}</span><h2>${o.title}</h2>${o.action||""}</div>${o.visual||""}<div class="metricValue">${o.value}</div>${o.sub?`<p class="metricSub">${o.sub}</p>`:""}${o.foot?`<p class="metricFoot">${o.foot}</p>`:""}</article>`; }
  function stats(){ if(!profile()) return needProfile(); const p=profile(), m=state.metrics.filter(x=>x.profileId===p.id).sort((a,b)=>new Date(a.measuredAt)-new Date(b.measuredAt)), acts=state.activities.filter(x=>x.profileId===p.id).sort((a,b)=>new Date(a.startedAt||0)-new Date(b.startedAt||0)), done=state.sessionRuns.filter(x=>x.profileId===p.id&&x.completedAt), last=m[m.length-1]||{}, prev=m.slice(0,-1).reverse().find(x=>x.weightKg), trend=last.weightKg&&prev?.weightKg?(last.weightKg-prev.weightKg).toFixed(1):"--", run=lastRun(acts), pain=Math.max(p.health.backPain,p.health.kneePain,p.health.tendonPain), readiness=Math.max(0,Math.min(100,76+Math.min(done.length,6)*3-pain*12-(p.health.fatigue||0)*6)), weightFoot=last.measuredAt?`Mis à jour le ${new Date(last.measuredAt).toLocaleDateString("fr-FR",{day:"2-digit",month:"long"})}`:"Garmin Index S2 ou saisie manuelle", runFoot=run?.startedAt?new Date(run.startedAt).toLocaleDateString("fr-FR",{day:"2-digit",month:"long"}):"Aucune activité importée"; return `<section class="statsPage"><div class="statsHero"><div><p class="eyebrow">Dashboard</p><h1

  // Porter ici les vues secondaires les plus denses :
  // statistiques détaillées, modales et réglages.
>Statistiques</h1></div><span class="pill">${state.sources.find(s=>s.id==="worker")?.enabled?"Garmin Worker prêt":"Offline local"}</span></div><div class="metricGrid">${metricCard({icon:"▣",title:"Poids",color:"var(--blue)",value:statsValue(last.weightKg," kg"),sub:`Objectif ${statsValue(p.targetWeightKg," kg")} · variation ${trend} kg`,foot:weightFoot,visual:spark(m.slice(-8),"weightKg","var(--blue)")})}${metricCard({icon:"◔",title:"Préparation",color:"var(--green)",value:readiness,sub:readiness>=75?"Haute · écoute ton corps":readiness>=50?"Correcte · reste facile":"Protection · réduire l'intensité",visual:gauge(readiness,"var(--green)",true)})}${metricCard({icon:"⌁",title:"Dernière activité",color:"var(--orange)",value:run?.distanceKm?`${run.distanceKm} km`:"--",sub:`${run?.durationSeconds?sec(Math.round(run.durationSeconds)):"--"} · ${paceLabel(run)}`,foot:runFoot})}${metricCard({icon:"♥",title:"Fréquence cardiaque",color:"var(--red)",value:statsValue(run?.hrAvg," bpm"),sub:`Repos ${statsValue(last.restingHr||run?.restingHr," bpm")} · max ${statsValue(run?.hrMax," bpm")}`,visual:gauge(run?.hrAvg?Math.min(100,run.hrAvg/190*100):0,"var(--red)")})}${metricCard({icon:"◷",title:"Assiduité",color:"var(--purple)",value:done.length,sub:"Séances terminées",visual:spark(done.map((x,i)=>({i:i+1,value:i+1})),"value","var(--purple)")})}${metricCard({icon:"◎",title:"Composition",color:"var(--orange)",value:statsValue(last.bodyFatPct," %"),sub:`Eau ${statsValue(last.waterPct," %")} · IMC ${statsValue(last.bmi)}`,foot:`Tour ventre ${statsValue(last.waistCm," cm")}`})}</div><div class="grid two"><article class="panel"><h2>Poids / tour ventre</h2>${chart(m,"weightKg","waistCm")}</article><article class="panel"><h2>Course et marche</h2>${bar(acts.filter(a=>a.type==="run"||a.type==="walk").slice(-10).map(a=>({label:new Date(a.startedAt).toLocaleDateString("fr-FR",{day:"2-digit",month:"2-digit"}),value:a.distanceKm||a.durationSeconds/600})))}</article></div><article class="panel inputPanel"><h2>Pesée manuelle / Garmin Index S2</h2><div class="grid four">${["weightKg:Poids kg","bodyFatPct:% graisse","waterPct:% eau","bmi:IMC","boneKg:Masse os kg","muscleKg:Masse muscle kg","waistCm:Tour ventre cm"].map(x=>{const [id,l]=x.split(":");return `<label>${l}<input id="${id}" type="number" step="0.1"></label>`}).join("")}</div><button class="primary" id="addMetric">Ajouter pesée</button></article><article class="panel inputPanel"><h2>Course / marche manuelle</h2><div class="grid four">${["runDistance:Distance km","runDuration:Durée min","runPace:Vitesse moy km/h","runHrAvg:FC moyenne","runHrMax:FC max","runFeeling:Ressenti 1-10","runPain:Douleur 0-5"].map(x=>{const [id,l]=x.split(":");return `<label>${l}<input id="${id}" type="number" step="0.1"></label>`}).join("")}<label>Type<select id="runType"><option value="run">Course</option><option value="walk">Marche</option><option value="bike">Vélo/cardio</option></select></label></div><button class="primary" id="addRun">Ajouter activité</button></article></section>`; }
  function readinessLabel(v){ return v>=75?["Haute","Séance prévue possible."]:v>=50?["Correcte","Reste facile."]:["Protection","Volume réduit."]; }
  function hrZones(max){ const m=Number(max)||190; return [{label:"Z1 facile",value:`${Math.round(m*.50)}-${Math.round(m*.60)} bpm`},{label:"Z2 endurance",value:`${Math.round(m*.60)}-${Math.round(m*.70)} bpm`},{label:"Z3 soutenu",value:`${Math.round(m*.70)}-${Math.round(m*.80)} bpm`},{label:"Z4 dur",value:`${Math.round(m*.80)}-${Math.round(m*.90)} bpm`}]; }
  function stats(){ if(!profile()) return needProfile(); const p=profile(), m=state.metrics.filter(x=>x.profileId===p.id).sort((a,b)=>new Date(a.measuredAt)-new Date(b.measuredAt)), acts=state.activities.filter(x=>x.profileId===p.id).sort((a,b)=>new Date(a.startedAt||0)-new Date(b.startedAt||0)), done=state.sessionRuns.filter(x=>x.profileId===p.id&&x.completedAt), last=m[m.length-1]||{}, prev=m.slice(0,-1).reverse().find(x=>x.weightKg), trend=last.weightKg&&prev?.weightKg?(last.weightKg-prev.weightKg).toFixed(1):"--", run=lastRun(acts), pain=Math.max(p.health.backPain||0,p.health.kneePain||0,p.health.tendonPain||0), readiness=Math.max(0,Math.min(100,76+Math.min(done.length,6)*3-pain*12-(p.health.fatigue||0)*6)), ready=readinessLabel(readiness), restHr=last.restingHr||run?.restingHr, avgHr=run?.hrAvg, maxHr=run?.hrMax||Math.round(208-(0.7*(p.age||40))), weightFoot=last.measuredAt?`Mis à jour le ${new Date(last.measuredAt).toLocaleDateString("fr-FR",{day:"2-digit",month:"long"})}`:"Garmin Index S2 ou saisie manuelle", runFoot=run?.startedAt?new Date(run.startedAt).toLocaleDateString("fr-FR",{day:"2-digit",month:"long"}):"Aucune activité importée"; return `<section class="statsPage"><div class="statsHero"><div><p class="eyebrow">Dashboard</p><h1>Statistiques</h1></div><span class="pill">${state.sources.find(s=>s.id==="worker")?.enabled?"Garmin Worker prêt":"Offline local"}</span></div><div class="metricGrid">${metricCard({icon:"▣",title:"Poids",color:"var(--blue)",value:statsValue(last.weightKg," kg"),sub:`Objectif ${statsValue(p.targetWeightKg," kg")} · variation ${trend} kg`,foot:weightFoot,visual:spark(m.slice(-8),"weightKg","var(--blue)")})}${metricCard({icon:"◔",title:"Préparation",color:"var(--green)",value:readiness,sub:`${ready[0]} · ${ready[1]}`,action:`<button class="infoButton" id="openReadinessInfo" aria-label="Information préparation">i</button>`,visual:gauge(readiness,readiness>=75?"var(--green)":readiness>=50?"var(--orange)":"var(--red)",true)})}${metricCard({icon:"⌁",title:"Dernière activité",color:"var(--orange)",value:run?.distanceKm?`${run.distanceKm} km`:"--",sub:`${run?.durationSeconds?sec(Math.round(run.durationSeconds)):"--"} · ${paceLabel(run)}`,foot:runFoot})}${metricCard({icon:"♥",title:"Cardio",color:"var(--red)",value:statsValue(maxHr," bpm"),sub:`FC max · repos ${statsValue(restHr," bpm")} · moyenne ${statsValue(avgHr," bpm")}`,visual:gauge(avgHr?Math.min(100,avgHr/maxHr*100):0,"var(--red)")})}${metricCard({icon:"◷",title:"Assiduité",color:"var(--purple)",value:done.length,sub:"Séances terminées",visual:spark(done.map((x,i)=>({i:i+1,value:i+1})),"value","var(--purple)")})}${metricCard({icon:"◎",title:"Composition",color:"var(--orange)",value:statsValue(last.bodyFatPct," %"),sub:`Eau ${statsValue(last.waterPct," %")} · IMC ${statsValue(last.bmi)}`,foot:`Tour ventre ${statsValue(last.waistCm," cm")}`})}</div><div class="grid two"><article class="panel graphPanel" id="openWeightChart"><h2>Poids / cible</h2>${chart(m,"weightKg",null,p.targetWeightKg)}</article><article class="panel"><h2>Tour de ventre</h2>${chart(m,"waistCm",null,null)}</article><article class="panel"><h2>Zones cardio estimées</h2><div class="zoneList">${hrZones(maxHr).map(z=>`<div class="row"><span>${z.label}</span><strong>${z.value}</strong></div>`).join("")}</div></article><article class="panel"><h2>Course et marche</h2>${bar(acts.filter(a=>a.type==="run"||a.type==="walk").slice(-10).map(a=>({label:new Date(a.startedAt).toLocaleDateString("fr-FR",{day:"2-digit",month:"2-digit"}),value:a.distanceKm||a.durationSeconds/600})))}</article></div></section>`; }
  function modalLayer(){ if(!state.ui.modal) return ""; const close=`<button class="iconClose" id="closeModal" aria-label="Fermer">×</button>`; if(state.ui.modal==="metric") return `<div class="modalShade fullModal"><section class="modalSheet"><header><div><p class="eyebrow">Aujourd'hui</p><h1>Ajouter une pesée</h1></div>${close}</header><div class="grid two">${["weightKg:Poids kg","bodyFatPct:% graisse","waterPct:% eau","bmi:IMC","boneKg:Masse os kg","muscleKg:Masse muscle kg","waistCm:Tour ventre cm"].map(x=>{const [id,l]=x.split(":");return `<label>${l}<input id="${id}" type="number" step="0.1"></label>`}).join("")}</div><button class="primary" id="addMetric">Enregistrer pesée</button></section></div>`; if(state.ui.modal==="activity") return `<div class="modalShade fullModal"><section class="modalSheet"><header><div><p class="eyebrow">Aujourd'hui</p><h1>Ajouter une activité</h1></div>${close}</header><div class="grid two">${["runDistance:Distance km","runDuration:Durée min","runPace:Vitesse moy km/h","runHrAvg:FC moyenne","runHrMax:FC max"].map(x=>{const [id,l]=x.split(":");return `<label>${l}<input id="${id}" type="number" step="0.1"></label>`}).join("")}<label>Type<select id="runType"><option value="run">Course</option><option value="walk">Marche</option><option value="bike">Vélo/cardio</option></select></label></div><h3>Ressenti</h3><div class="smileyGrid quickSmiley">${ratingControl("runFeeling","Ressenti",null)}${ratingControl("runPain","Douleur",null)}</div><button class="primary" id="addRun">Enregistrer activité</button></section></div>`; if(state.ui.modal==="newProfile") return `<div class="modalShade fullModal"><section class="modalSheet"><header><div><p class="eyebrow">Réglages</p><h1>Nouveau profil</h1></div>${close}</header>${newProfileBox()}</section></div>`; if(state.ui.modal==="readiness") return `<div class="modalShade"><section class="modalSheet"><header><div><p class="eyebrow">Indicateur</p><h1>Préparation</h1></div>${close}</header><p>La préparation combine les séances terminées, la douleur dos/genou/tendon et la fatigue. Elle ne remplace pas un avis médical.</p><div class="zoneList"><div class="row"><span>Vert</span><strong>75-100 : séance prévue possible</strong></div><div class="row"><span>Orange</span><strong>50-74 : rester facile</strong></div><div class="row"><span>Rouge</span><strong>0-49 : volume réduit</strong></div></div></section></div>`; if(state.ui.modal==="weightChart"){ const p=profile(), rows=state.metrics.filter(x=>x.profileId===p.id).sort((a,b)=>new Date(a.measuredAt)-new Date(b.measuredAt)); return `<div class="modalShade fullModal"><section class="modalSheet wide"><header><div><p class="eyebrow">Graphique</p><h1>Poids et cible</h1></div>${close}</header>${chart(rows,"weightKg",null,p.targetWeightKg,true)}<h2>Tour de ventre</h2>${chart(rows,"waistCm",null,null,true)}</section></div>`; } return ""; }
  function foldPanel(title,content,cls=""){ return `<details class="panel settingsFold ${cls}"><summary>${title}</summary>${content}</details>`; }
  function settings(){ const profileRows=state.profiles.map(x=>`<details class="profileFold"><summary><span>${esc(x.name)}</span><strong>${x.id===state.activeProfileId?"Actif":"Inactif"}</strong></summary>${x.id===state.activeProfileId?profileForm(x):`<button class="secondary" data-profile="${x.id}">Choisir ce profil</button>`}</details>`).join("")||"<p>Aucun profil.</p>", appearance=`<article class="panel appearancePanel"><h2>Apparence</h2><div class="segmentedSwitch compactSegmented" role="group" aria-label="Thème">${["auto:Auto","dark:Sombre","light:Clair"].map(x=>{const [id,l]=x.split(":");return `<button class="secondary ${state.settings.theme===id?"active":""}" data-theme-choice="${id}">${l}</button>`}).join("")}</div></article>`, profiles=`<article class="panel profilePanel"><h2>Profils</h2>${profileRows}<button class="primary" id="openNewProfile">Créer un nouveau profil</button></article>`, reminders=`<div class="reminderInlineRow"><div class="reminderToggle">${yesNoSwitch("notifEnabled","Rappel actif",state.settings.notifications.enabled)}</div><label class="timeCompact"><span>Heure :</span><input id="notifTime" type="time" value="${esc(state.settings.notifications.reminderTime||"08:00")}"></label></div><div class="row"><span>Autorisation</span><strong id="notificationStatus">${esc(notificationStatusText())}</strong></div><p class="muted">Si l'app est installée, le badge reste géré automatiquement. Sur iPhone, l'autorisation est demandée à l'installation si possible. L'Apple Watch reprend les notifications selon les réglages de recopie iPhone.</p><div class="actions"><button class="secondary" id="testNotification">Tester notification</button></div>`, voice=`<div class="grid three"><label>Activé<select id="ttsEnabled"><option value="true" ${state.settings.tts.enabled?"selected":""}>Oui</option><option value="false" ${!state.settings.tts.enabled?"selected":""}>Non</option></select></label><label>Vitesse<input id="ttsRate" type="number" min="0.7" max="1.4" step="0.1" value="${state.settings.tts.rate}"></label><label>Volume<input id="ttsVolume" type="number" min="0" max="1" step="0.1" value="${state.settings.tts.volume}"></label></div><button class="secondary" id="testVoice">Tester</button>`, workerBox=`<label>URL Worker<input id="workerUrl" value="${esc(state.settings.workerUrl)}"></label><label>Token app<input id="workerToken" value="${esc(state.settings.workerToken)}" type="password"></label><div class="actions"><button class="secondary" id="testWorker">Tester</button><button class="secondary" id="mockGarmin">Mock Garmin</button></div>`, exportBox=`<div class="actions"><button class="primary" id="exportJson">Exporter sans secrets</button><button class="secondary" id="exportJsonSecrets">Exporter avec token Worker</button><label class="secondary file">Importer JSON<input id="importJson" type="file" accept="application/json"></label></div>`, appBox=`<div class="row"><span>Version installée</span><strong>v${APP_VERSION}</strong></div><div class="row"><span>Version en ligne</span><strong>${esc(remoteVersion||APP_VERSION)}</strong></div><p class="muted">La PWA vérifie automatiquement les mises à jour au lancement et quand le réseau revient. Les données IndexedDB restent locales.</p>`, maintenance=`<button class="danger strongDanger" id="deleteProfile">Supprimer profil actif</button><button class="danger strongDanger" id="resetAll">Tout effacer localement</button>`; return `<section class="grid"><h1>Réglages</h1>${appearance}${profiles}${foldPanel("Rappels séance",reminders)}${foldPanel("Coach vocal",voice)}${foldPanel("Worker Garmin optionnel",workerBox)}${foldPanel("Export / import JSON",exportBox)}${foldPanel("Application",appBox)}${foldPanel("Maintenance",maintenance,"maintenancePanel")}</section>`; }
  function newProfileBox(){ return `<div class="newProfile"><div class="grid four"><label>Nom du profil<input id="newProfileName" placeholder="Prénom ou pseudo"></label><label>Sexe<select id="newGender"><option value="male">Homme</option><option value="female">Femme</option></select></label><label>Âge<input id="newAge" type="number"></label><label>Taille cm<input id="newHeight" type="number"></label><label>Poids départ kg<input id="newWeight" type="number" step="0.1"></label><label>Objectif kg<input id="newTarget" type="number" step="0.1"></label><label>Durée objectif mois<input id="newTargetMonths" type="number" min="6" value="6"></label></div><button class="primary" id="createProfile">Créer nouveau profil</button></div>`; }
  function yesNoSwitch(id,label,value){ return `<label class="booleanSwitch"><span class="switchLabel">${label}</span><input id="${id}" type="checkbox" ${value?"checked":""}><span class="switchPill"><span class="switchState">${value?"Oui":"Non"}</span><span class="switchKnob"></span></span></label>`; }
  function profileForm(p){ const g=goalInfo(p), windowDays=weekWindowDays(p); return `<div class="profileEditor"><div class="grid four"><label>Nom<input id="profileName" value="${esc(p.name)}"></label><label>Sexe<select id="gender"><option value="male" ${(p.gender||"male")==="male"?"selected":""}>Homme</option><option value="female" ${p.gender==="female"?"selected":""}>Femme</option></select></label><label>Âge<input id="age" type="number" value="${p.age||""}"></label><label>Taille cm<input id="heightCm" type="number" value="${p.heightCm||""}"></label><label>Poids départ<input id="startWeightKg" type="number" step="0.1" value="${p.startWeightKg||""}"></label><label>Poids objectif<input id="targetWeightKg" type="number" step="0.1" value="${p.targetWeightKg||""}"></label><label>Durée objectif mois<input id="targetMonths" type="number" min="6" value="${p.targetMonths||6}"></label></div><div class="segmentedSwitch compactSegmented" role="group" aria-label="Fenêtre de planification"><button class="secondary ${windowDays===5?"active":""}" data-week-window="5">Semaine 5 jours</button><button class="secondary ${windowDays===7?"active":""}" data-week-window="7">Semaine 7 jours</button></div><p class="notice goalGuard">Garde-fou objectif : minimum 6 mois et maximum 5 kg/mois. Cadence actuelle : ${esc(g.text)}. Matériel prévu : poids du corps, chaise ou banc, élastique.</p><label>Historique sportif<textarea id="sportsHistory">${esc(p.sportsHistory)}</textarea></label><h3>État du corps</h3><p class="muted">5 = tout va bien, 0 = alerte rouge. Si Genoux / Tendons est à 3/5 ou moins, le plan exclut squat, fente, pliométrie et step, mais conserve marche-course ou course très facile sur plat, 45 min maximum.</p>${bodyStateControls("profile",p,"quickSmiley bodyStateGrid")}<div class="safetySwitchRow">${yesNoSwitch("irradiating","Douleur irradiée",p.health.irradiating)}${yesNoSwitch("neurological","Signe neurologique",p.health.neurological)}</div><h3>Tests initiaux</h3><p class="muted">Choisis le niveau réel confortable, pas le maximum possible. Le plan progresse mieux avec une base facile et propre.</p>${levelHelp()}<div class="grid three">${Object.keys(levels).map(k=>`<label>${levelNames[k]}<select id="level_${k}">${levelOptions(k,p.levels[k])}</select></label>`).join("")}</div><button class="primary" id="regenProfilePlan">Regénérer le plan</button></div>`; }

  // Générer les fiches d'exercices et les zones anatomiques à partir de la bibliothèque centrale.
  function needProfile(){ return `<section class="hero"><h1>Profil requis</h1><p>Crée un profil pour activer cette page.</p>${newProfileBox()}</section>`; }
  function videoSrc(x){ const p=state.exerciseVideos?.[x.id]||x.videoPath||"/"; return /^https?:\/\//.test(p)?p:(state.settings.videoBase||videos.defaultBase)+p; }
  function media(x,compact=false){ const raw=state.exerciseVideos?.[x.id]||x.videoPath||"", hasVideo=!!raw&&raw!=="/"&&/\.mp4($|\?)/i.test(raw), src=hasVideo?videoSrc(x):""; return `${hasVideo?`<div class="videoFrame"><video controls playsinline preload="metadata" src="${esc(src)}"></video></div>`:""}<details ${compact?"":"open"}><summary>Schéma animé offline</summary>${diagram(x)}</details>`; }
  function card(x){ return `<article class="panel exercise"><div class="media">${media(x)}</div><div class="exerciseTitle"><div><p class="eyebrow">${familyLabel(x.family)} · ${x.type} · ${x.sets} série(s)</p><h2>${x.name}</h2></div><details class="editExercise"><summary title="Modifier l'URL vidéo">✎</summary><label>URL vidéo .mp4<input id="video_${x.id}" value="${esc(state.exerciseVideos?.[x.id]||x.videoPath||"")}" placeholder="https://...mp4"></label><button class="secondary" data-save-video="${x.id}">Enregistrer vidéo</button></details></div><p>${x.short}</p>${targetPanel(x)}<h3>Comment faire</h3><ol>${x.steps.map(s=>`<li>${esc(s)}</li>`).join("")}</ol>${x.sourceUrl?`<p><a class="textLink" href="${esc(x.sourceUrl)}" target="_blank" rel="noopener">Lien explicatif</a></p>`:""}<p class="notice">${x.safety}</p></article>`; }
  function targets(x){ const byId={dead_bug:["abdos profonds","lombaires stables"],bird_dog:["lombaires","fessiers","épaules"],front_plank:["abdos","épaules"],side_plank_knees:["obliques","hanches"],hollow_hold:["abdos"],wall_pushup:["pectoraux","triceps"],incline_pushup:["pectoraux","épaules","triceps"],knee_pushup:["pectoraux","triceps"],pike_pushup:["épaules","triceps"],band_row:["haut du dos","biceps"],band_pulldown:["grand dorsal","haut du dos"],reverse_fly:["arrière épaules","haut du dos"],sit_to_stand:["cuisses","fessiers"],box_squat:["cuisses","fessiers"],split_squat:["cuisses","fessiers"],glute_bridge:["fessiers","ischios"],calf_raise:["mollets"],hip_hinge:["ischios","fessiers","dos stable"],quad_set:["quadriceps","rotule"],straight_leg_raise:["quadriceps","hanche"],seated_knee_extension:["quadriceps","rotule"],standing_hamstring_curl:["ischios","genou"],clamshell:["moyen fessier","hanche"],hip_abduction_side:["moyen fessier","axe genou"],hip_flexor:["psoas","hanches"],thoracic_rotation:["haut du dos"],ankle_wall:["chevilles","mollets"],hamstring_floss:["ischios"],shoulder_wall_slide:["épaules","haut du dos"],brisk_walk:["cardio","mollets"],easy_run:["cardio","jambes"],run_walk:["cardio","jambes"],low_impact_cardio:["cardio"],step_up_low:["cuisses","fessiers"],warmup_flow:["mobilité globale"],cooldown_breathing:["respiration"]}; return byId[x.id]||({core:["abdos","dos stable"],push:["pectoraux","épaules"],pull:["dos","bras"],legs:["cuisses","fessiers"],knee_rehab:["genou","hanche"],mobility:["mobilité"],cardio:["coeur","jambes"]}[x.family]||["corps entier"]); }
  function targetPanel(x){ return `<div class="targetPanel">${muscleMap(x)}<div><p class="eyebrow">Zones travaillées</p><div class="targetChips">${targets(x).map(t=>`<span>${esc(t)}</span>`).join("")}</div></div></div>`; }

  // Produire ici les schémas SVG offline.
  // Le rendu reste volontairement simple pour rester robuste sans dépendance externe.
  function poseLine(p,cls="",op=1){ const q=k=>p[k], line=(a,b)=>`<line x1="${q(a)[0]}" y1="${q(a)[1]}" x2="${q(b)[0]}" y2="${q(b)[1]}"/>`; return `<g class="pose ${cls}" opacity="${op}"><circle cx="${p.head[0]}" cy="${p.head[1]}" r="13"/><path d="M${p.neck[0]} ${p.neck[1]} Q ${p.mid[0]} ${p.mid[1]} ${p.hip[0]} ${p.hip[1]}"/>${line("neck","lhand")}${line("neck","rhand")}${line("hip","lknee")}${line("lknee","lfoot")}${line("hip","rknee")}${line("rknee","rfoot")}</g>`; }
  function poseTemplate(x){ const map={dead_bug:["Dos au sol","Bras/jambe opposés descendent", {head:[72,148],neck:[95,150],mid:[160,162],hip:[224,151],lhand:[126,82],rhand:[176,82],lknee:[160,96],lfoot:[194,96],rknee:[224,98],rfoot:[260,98]}, {head:[72,148],neck:[95,150],mid:[160,162],hip:[224,151],lhand:[72,94],rhand:[176,82],lknee:[160,96],lfoot:[194,96],rknee:[272,158],rfoot:[318,170]}], hollow_hold:["Dos plaqué","Éloigne bras et jambes sans cambrer", {head:[80,145],neck:[105,150],mid:[168,162],hip:[230,154],lhand:[132,82],rhand:[160,82],lknee:[230,110],lfoot:[270,112],rknee:[245,116],rfoot:[288,122]}, {head:[80,145],neck:[105,150],mid:[168,162],hip:[230,154],lhand:[84,88],rhand:[110,80],lknee:[274,150],lfoot:[328,162],rknee:[280,158],rfoot:[338,175]}], bird_dog:["À quatre pattes","Tends bras et jambe opposés", {head:[105,101],neck:[126,112],mid:[188,136],hip:[246,136],lhand:[122,184],rhand:[172,184],lknee:[238,186],lfoot:[222,206],rknee:[286,186],rfoot:[304,206]}, {head:[105,101],neck:[126,112],mid:[188,136],hip:[246,136],lhand:[62,126],rhand:[172,184],lknee:[238,186],lfoot:[222,206],rknee:[320,122],rfoot:[365,110]}], plank:["Corps droit","Garde la ligne épaules-hanches", {head:[92,118],neck:[118,127],mid:[202,138],hip:[282,146],lhand:[95,182],rhand:[124,184],lknee:[300,180],lfoot:[350,184],rknee:[302,178],rfoot:[362,183]}, {head:[92,116],neck:[118,126],mid:[202,134],hip:[282,142],lhand:[95,182],rhand:[124,184],lknee:[300,180],lfoot:[350,184],rknee:[302,178],rfoot:[362,183]}], push:["Planche mains au sol","Descends puis repousse en bloc", {head:[96,112],neck:[124,124],mid:[200,139],hip:[280,154],lhand:[122,186],rhand:[154,190],lknee:[298,183],lfoot:[356,190],rknee:[300,183],rfoot:[365,190]}, {head:[96,146],neck:[124,156],mid:[200,166],hip:[280,176],lhand:[122,190],rhand:[154,194],lknee:[298,190],lfoot:[356,194],rknee:[300,190],rfoot:[365,194]}], squat:["Debout solide","Hanches arrière, genoux alignés", {head:[152,66],neck:[152,88],mid:[152,126],hip:[152,154],lhand:[120,132],rhand:[184,132],lknee:[134,194],lfoot:[112,210],rknee:[172,194],rfoot:[198,210]}, {head:[282,88],neck:[282,110],mid:[268,142],hip:[246,166],lhand:[235,136],rhand:[314,136],lknee:[220,196],lfoot:[190,210],rknee:[286,194],rfoot:[318,210]}], bridge:["Épaules au sol","Monte les hanches sans cambrer", {head:[82,156],neck:[106,158],mid:[170,170],hip:[238,168],lhand:[78,186],rhand:[115,184],lknee:[268,132],lfoot:[318,176],rknee:[286,138],rfoot:[350,176]}, {head:[82,156],neck:[106,158],mid:[170,148],hip:[238,118],lhand:[78,186],rhand:[115,184],lknee:[268,132],lfoot:[318,176],rknee:[286,138],rfoot:[350,176]}],

  // Regrouper ici les helpers de visualisation, d'import/export,
  // de communication Worker et de cycle de vie PWA.
pull:["Posture haute","Tire les coudes vers l'arrière", {head:[172,74],neck:[172,96],mid:[172,136],hip:[172,170],lhand:[252,120],rhand:[252,120],lknee:[150,206],lfoot:[130,222],rknee:[194,206],rfoot:[218,222]}, {head:[172,74],neck:[172,96],mid:[172,136],hip:[172,170],lhand:[204,126],rhand:[210,126],lknee:[150,206],lfoot:[130,222],rknee:[194,206],rfoot:[218,222]}], cardio:["Foulée courte","Reste facile et régulier", {head:[142,76],neck:[142,98],mid:[132,136],hip:[122,166],lhand:[96,126],rhand:[178,124],lknee:[100,194],lfoot:[68,218],rknee:[154,190],rfoot:[202,206]}, {head:[260,76],neck:[260,98],mid:[250,136],hip:[240,166],lhand:[296,126],rhand:[218,124],lknee:[268,190],lfoot:[318,206],rknee:[218,194],rfoot:[184,218]}], mobility:["Amplitude douce","Bouge lentement sans forcer", {head:[166,66],neck:[166,88],mid:[166,130],hip:[166,168],lhand:[118,112],rhand:[214,112],lknee:[144,204],lfoot:[122,222],rknee:[188,204],rfoot:[214,222]}, {head:[250,66],neck:[250,88],mid:[238,130],hip:[226,168],lhand:[170,104],rhand:[318,82],lknee:[204,204],lfoot:[178,222],rknee:[250,204],rfoot:[278,222]}]}; if(map[x.id]) return map[x.id]; if(["front_plank","side_plank_knees"].includes(x.id)) return map.plank; if(x.family==="push") return map.push; if(x.family==="pull") return map.pull; if(["glute_bridge"].includes(x.id)) return map.bridge; if(x.family==="legs") return map.squat; if(x.family==="cardio") return map.cardio; if(x.family==="knee_rehab") return map.mobility; if(x.family==="mobility"||x.family==="warmup"||x.family==="cooldown") return map.mobility; return map.mobility; }
  function poseDiagram(x){ const [a,b,start,end]=poseTemplate(x), c={core:"#4f9cff",push:"#f57b45",pull:"#7c6cff",legs:"#5dbb63",knee_rehab:"#19a974",mobility:"#b9f66b",cardio:"#ff5c7a",warmup:"#49c6b7",cooldown:"#9aa5a1"}[x.family]||"#4f9cff"; return `<svg class="exoSvg poseSvg" viewBox="0 0 420 250" role="img" aria-label="${esc(x.name)}"><rect width="420" height="250" rx="20" fill="#eef5ef"/><text x="22" y="31" font-size="18" font-family="Arial" font-weight="800" fill="#12231f">${esc(x.name)}</text><path d="M42 222h336" stroke="#d1dfd5" stroke-width="8" stroke-linecap="round"/><g class="poseStart">${poseLine(start,"",.22)}</g><g class="poseMove">${poseLine(end)}</g><path d="M112 52 C170 28 247 28 306 52" fill="none" stroke="${c}" stroke-width="8" stroke-linecap="round"/><path d="M296 42 l22 11 l-22 11" fill="none" stroke="${c}" stroke-width="8" stroke-linecap="round" stroke-linejoin="round"/><text x="34" y="236" fill="#62716b" font-size="13">${esc(a)}</text><text x="212" y="236" fill="#62716b" font-size="13">${esc(b)}</text></svg>`; }
  function diagram(x){ return poseDiagram(x); }
  function bodyPartIds(x){ const t=targets(x).join(" ").toLowerCase(), has=s=>t.includes(s), ids=new Set(); if(has("abdos")||has("oblique")||has("respiration")) ["abdominals","obliques"].forEach(i=>ids.add(i)); if(has("pectoraux")) ids.add("chest"); if(has("épaule")||has("arrière épaules")) ["front-shoulders","rear-shoulders","shoulders","traps"].forEach(i=>ids.add(i)); if(has("dos")||has("dorsal")||has("haut du dos")) ["lats","traps","traps-middle","lowerback","rear-shoulders"].forEach(i=>ids.add(i)); if(has("lombaire")) ["lowerback","lats"].forEach(i=>ids.add(i)); if(has("fessier")||has("hanche")) ["hips","glutes"].forEach(i=>ids.add(i)); if(has("cuisse")||has("ischios")||has("jambes")) ["quads","hamstrings"].forEach(i=>ids.add(i)); if(has("mollet")||has("cheville")) ["calves","ankles"].forEach(i=>ids.add(i)); if(has("bras")||has("biceps")) ids.add("biceps"); if(has("triceps")) ids.add("triceps"); if(has("cardio")||has("coeur")) ["quads","calves","hamstrings"].forEach(i=>ids.add(i)); return [...ids]; }
  function injectedBodyMap(kind, ids, label){ let svg=bodyMapSvg[kind]||""; if(!svg) return `<img class="anatomyMap detailedBodyMap anatomyModel" src="${bodyMapAssets[kind]}" alt="${esc(label)}">`; svg=svg.replace(/<svg\b([^>]*)>/,(m,attrs)=>{ const cleaned=attrs.replace(/\sclass="[^"]*"/,"").replace(/\srole="[^"]*"/,"").replace(/\saria-label="[^"]*"/,""); return `<svg${cleaned} class="anatomyMap detailedBodyMap anatomyModel" role="img" aria-label="${esc(label)}">`; }); ids.forEach(id=>{ svg=svg.replace(new RegExp(`(<[^>]*\\bid="${id}"[^>]*\\bclass=")([^"]*)(")`,`g`),`$1hot $2$3`); svg=svg.replace(new RegExp(`(<[^>]*\\bclass=")([^"]*)("[^>]*\\bid="${id}"[^>]*>)`,`g`),`$1hot $2$3`); }); return svg; }
  function muscleMap(x){ const kind=profile()?.gender==="female"?"female":"male"; return injectedBodyMap(kind,bodyPartIds(x),`Zones travaillées ${x.name}`); }
  function chart(rows,a,b,target=null,large=false){ if(!rows.length) return "<p class='muted'>Aucune donnée.</p>"; const vals=rows.flatMap(r=>b?[Number(r[a]),Number(r[b])]:[Number(r[a])]).filter(Number.isFinite); if(target!=null) vals.push(Number(target)); if(!vals.length) return "<p class='muted'>Aucune donnée.</p>"; const min=Math.min(...vals), max=Math.max(...vals), W=large?820:520,H=large?310:190, x=i=>30+i*(W-60)/Math.max(1,rows.length-1), y=v=>H-24-((v-min)/Math.max(1,max-min)*(H-55)), pts=k=>rows.map((r,i)=>`${x(i)},${y(Number(r[k])||min)}`).join(" "), targetY=target!=null?y(Number(target)):null, legend=b?"bleu poids · vert cible · orange ventre":(a==="waistCm"?"tour de ventre":"bleu poids · vert cible"); return `<svg class="chart ${large?"chartLarge":""}" viewBox="0 0 ${W} ${H}"><rect width="${W}" height="${H}" rx="12" fill="var(--chart-bg)"/>${targetY?`<line x1="30" y1="${targetY}" x2="${W-30}" y2="${targetY}" stroke="var(--green)" stroke-width="3" stroke-dasharray="8 8"/><text x="${W-150}" y="${targetY-8}" fill="var(--green)">cible ${target} kg</text>`:""}<polyline points="${pts(a)}" fill="none" stroke="var(--blue)" stroke-width="4"/>${b?`<polyline points="${pts(b)}" fill="none" stroke="var(--orange)" stroke-width="4"/>`:""}<text x="24" y="24" fill="var(--muted)">${legend}</text></svg>`; }
  function bar(rows){ if(!rows.length) return "<p class='muted'>Aucune activité.</p>"; const max=Math.max(...rows.map(r=>r.value),1); return `<div class="bars">${rows.map(r=>`<div><span style="height:${Math.max(8,r.value/max*120)}px"></span><small>${esc(r.label)}</small></div>`).join("")}</div>`; }
  function addMetric(){ const p=profile(), w=num("weightKg"); if(!p||!w) return; state.metrics.push({id:uid("metric"),profileId:p.id,source:"manual",measuredAt:new Date().toISOString(),weightKg:w,bodyFatPct:num("bodyFatPct"),waterPct:num("waterPct"),bmi:num("bmi"),boneKg:num("boneKg"),muscleKg:num("muscleKg"),waistCm:num("waistCm")}); state.ui.modal=null; save("Pesée enregistrée.").then(render); }
  function addRun(){ const p=profile(); if(!p) return; state.activities.push({id:uid("activity"),profileId:p.id,source:"manual",type:el("runType").value,startedAt:new Date().toISOString(),distanceKm:num("runDistance"),durationSeconds:num("runDuration")?num("runDuration")*60:null,avgSpeedKmh:num("runPace"),hrAvg:num("runHrAvg"),hrMax:num("runHrMax"),feeling:num("runFeeling"),pain:num("runPain")}); state.ui.modal=null; save("Activité enregistrée.").then(render); }
  function exportJson(secret=false){ const c=clone(state); if(!secret)c.settings.workerToken=""; const a=document.createElement("a"); a.href=URL.createObjectURL(new Blob([JSON.stringify({exportedAt:new Date().toISOString(),...c},null,2)],{type:"application/json"})); a.download=`resurgo-export-${TODAY}.json`; a.click(); URL.revokeObjectURL(a.href); }
