    normalizeGoal(p);
    p.health.backPain=loadScore("profileBack");
    p.health.kneePain=loadScore("profileKnee");
    p.health.tendonPain=loadScore("profileKnee");
    p.health.fatigue=loadScore("profileFatigue");
